from hashlib import md5

class SimpleConsistentHasher:
    def __init__(self, nodes):
        self.ring = []
        for node in nodes:
            h = int(md5(node.encode()).hexdigest(), 16)
            self.ring.append((h, node))
        self.ring.sort()

    def get_node(self, key):
        h = int(md5(key.encode()).hexdigest(), 16)
        for node_hash, node in self.ring:
            if h <= node_hash:
                return node
        return self.ring[0][1]

# Example usage
nodes = ['shard1', 'shard2', 'shard3']
hasher = SimpleConsistentHasher(nodes)
print(hasher.get_node('user:12345'))

