  try {
    await step(id, 1, () => reserveFlight(payload.flight), () => cancelFlight(payload.flight));
    await step(id, 2, () => reserveHotel(payload.hotel), () => cancelHotel(payload.hotel));
    await step(id, 3, () => reserveCar(payload.car), () => cancelCar(payload.car));
    sagaStore.set(id, { step: 3, status: 'completed' });
    return { status: 'completed' };
  } catch (err) {
    await compensate(id);
    sagaStore.set(id, { status: 'failed', error: err.message });
    return { status: 'failed' };
  }
}

